package com.example.ecommerce.order.service;

import com.example.ecommerce.order.model.Order;
import com.example.ecommerce.order.model.OrderItem;
import javax.jws.WebService;
import java.math.BigDecimal;
import java.util.logging.Logger;

@WebService(endpointInterface = "com.example.ecommerce.order.service.OrderProcessingService",
            serviceName = "OrderProcessingWebService",
            portName = "OrderProcessingPort",
            targetNamespace = "http://service.order.ecommerce.example.com/")
public class OrderProcessingServiceImpl implements OrderProcessingService {

    private static final Logger LOGGER = Logger.getLogger(OrderProcessingServiceImpl.class.getName());

    @Override
    public String processOrder(Order order) throws Exception {
        if (order == null) {
            LOGGER.severe("Received null order.");
            throw new IllegalArgumentException("Order cannot be null.");
        }

        LOGGER.info("Received order ID: " + order.getOrderId() + ", Customer ID: " + order.getCustomerId());

        // 1. Calculate total price
        BigDecimal totalAmount = BigDecimal.ZERO;
        if (order.getItems() != null && !order.getItems().isEmpty()) {
            for (OrderItem item : order.getItems()) {
                if (item.getUnitPrice() == null || item.getQuantity() <= 0) {
                    LOGGER.warning("Invalid item details found for SKU: " + item.getSku() + ". Skipping calculation for this item.");
                    // In a real system, you might throw an exception or handle it differently
                    continue;
                }
                BigDecimal itemTotal = item.getUnitPrice().multiply(new BigDecimal(item.getQuantity()));
                totalAmount = totalAmount.add(itemTotal);
                LOGGER.info(String.format("  Item SKU: %s, Qty: %d, Unit Price: %.2f, Item Total: %.2f",
                        item.getSku(), item.getQuantity(), item.getUnitPrice(), itemTotal));
            }
        } else {
            LOGGER.info("Order " + order.getOrderId() + " has no items.");
        }
        order.setTotalAmount(totalAmount);
        LOGGER.info("Calculated total amount for order " + order.getOrderId() + ": " + totalAmount.toPlainString());

        // 2. Process order (placeholder for actual business logic)
        // This is where you would integrate with your database, ERP, inventory,
        // payment gateway, and other internal systems for B2B order fulfillment.
        LOGGER.info("Simulating advanced B2B order processing for order ID: " + order.getOrderId() + "...");
        // Example: Persist order to database, update inventory, notify sales, etc.
        Thread.sleep(100); // Simulate some processing time

        String confirmationMessage = "B2B Order " + order.getOrderId() + " for customer " + order.getCustomerId() +
                                     " successfully received and is being processed. Total amount: " + totalAmount.toPlainString();

        LOGGER.info(confirmationMessage);
        return confirmationMessage;
    }
}


